function getAccessory(lvl){return lvl>=100?ACCESSORIES[100]:ACCESSORIES[lvl]||null;}

function girlSVG(lvl){
  var rects="";
  for(var y=0;y<GIRL_MAP.length;y++){
    var row=GIRL_MAP[y];
    for(var x=0;x<row.length;x++){
      var c=row[x];
      if(GIRL_PAL[c]) rects+='<rect x="'+x+'" y="'+(y+GIRL_Y_OFFSET)+'" width="1" height="1" fill="'+GIRL_PAL[c]+'"/>';
    }
  }
  var acc=getAccessory(lvl||1);
  if(acc){acc.pixels.forEach(function(p){rects+='<rect x="'+p[0]+'" y="'+p[1]+'" width="1" height="1" fill="'+p[2]+'"/>';});}
  return '<svg viewBox="0 0 20 '+GIRL_SVG_H+'" width="100%" height="100%" shape-rendering="crispEdges" preserveAspectRatio="xMidYMid meet" xmlns="http://www.w3.org/2000/svg">'+rects+'</svg>';
}
function heartSVG(){
  var rects="",pts=[[1,0],[2,0],[4,0],[5,0],[0,1],[1,1],[2,1],[3,1],[4,1],[5,1],[6,1],[0,2],[1,2],[2,2],[3,2],[4,2],[5,2],[6,2],[1,3],[2,3],[3,3],[4,3],[5,3],[2,4],[3,4],[4,4]];
  pts.forEach(function(p){rects+='<rect x="'+p[0]+'" y="'+p[1]+'" width="1" height="1" fill="#ff4488"/>';});
  return '<svg viewBox="0 0 7 5" width="100%" height="100%" shape-rendering="crispEdges" xmlns="http://www.w3.org/2000/svg">'+rects+'</svg>';
}

document.getElementById("logo-heart").innerHTML=heartSVG();

