var KEY="uniquenpc_rpg_v2";
var state=load();
function load(){try{var r=localStorage.getItem(KEY);if(r){var d=JSON.parse(r);if(d.age===undefined)d.age=null;return d;}}catch(e){}return{unlocked:{},custom:[],age:null};}
function save(){try{localStorage.setItem(KEY,JSON.stringify(state));}catch(e){}}
function allAch(){return CATALOG.concat(state.custom);}
function unlockedList(){return allAch().filter(function(a){return state.unlocked[a.id];});}
var filterCat="all",searchTerm="";
function byId(x){return document.getElementById(x);}

var LVL_BASE=1000,LVL_MULT=1.2;
function levelCost(n){return Math.round(LVL_BASE*Math.pow(LVL_MULT,n-1));}
function levelFromXP(xp){var lvl=1,rem=xp,cost=levelCost(1);while(rem>=cost){rem-=cost;lvl++;cost=levelCost(lvl);}return{level:lvl,into:rem,need:cost};}
function computeStats(){
  var all=allAch(),unl=unlockedList();
  var xp=unl.reduce(function(s,a){return s+RARITY[a.rarity].xp;},0);
  var rare=unl.filter(function(a){return["rare","epic","legend"].indexOf(a.rarity)>=0;}).length;
  var age=(typeof state.age==="number"&&state.age>=0)?state.age:null;
  var ageClamped=age===null?0:Math.min(100,Math.max(0,age));
  var L=levelFromXP(xp);
  return{total:all.length,count:unl.length,xp:xp,rare:rare,age:age,agePct:Math.round(ageClamped/100*100),level:L.level,lvlInto:L.into,lvlNeed:L.need,lvlPct:Math.round(L.into/L.need*100)};
}
function renderStats(){
  var s=computeStats();
  byId("s-level").textContent=s.level;
  byId("s-lvlbar").style.width=s.lvlPct+"%";
  byId("s-lvlhint").textContent=s.lvlInto+" / "+s.lvlNeed+" XP";
  byId("s-agebar").style.width=s.agePct+"%";
  byId("s-unlocked").textContent=s.count;byId("s-total").textContent=s.total;
  byId("s-xp").innerHTML=s.xp+'<small> XP</small>';
  byId("s-pct").innerHTML=(s.age===null?'--':s.agePct)+'<small>%</small>';
  byId("p-level").textContent=(s.age===null?'--':s.age);
  byId("p-glevel").textContent=s.level;
  byId("p-unlocked").textContent=s.count;byId("p-xp").textContent=s.xp;
  byId("p-rare").textContent=s.rare;byId("p-pct").textContent=(s.age===null?'--':s.agePct+'%');
  var _acc=getAccessory(s.level);
  var _accEl=byId("p-acc");if(_accEl)_accEl.textContent=_acc?_acc.name:"Базовый облик";
  byId("scene-hero").innerHTML=girlSVG(s.level);
  byId("avatar-box").innerHTML=girlSVG(s.level);
}
function cardHTML(a){
  var r=RARITY[a.rarity],on=!!state.unlocked[a.id];
  var isCustom=a.id.indexOf("custom-")===0;
  var date=on&&state.unlocked[a.id].date?state.unlocked[a.id].date:null;
  return '<div class="card rarity-'+a.rarity+' '+(on?'unlocked':'locked')+'" data-id="'+a.id+'">'+
    (isCustom?'<span class="tagcustom">МОЙ</span>':'')+
    '<div class="top"><div class="icon">'+iconSVG(a.ic)+'</div><span class="rarity">'+r.label+'</span></div>'+
    '<h3><span class="lk">'+(on?'■':'□')+'</span>'+a.t+'</h3>'+
    '<div class="desc">'+(a.d||'Свой личный квест')+'</div>'+
    '<div class="meta"><span>'+a.pct+'% ЛЮДЕЙ</span>'+
    (on&&date?'<span class="date">'+date+'</span>':'<span class="xp">+'+r.xp+'XP</span>')+'</div></div>';
}
function renderGrid(){
  var list=allAch();
  if(filterCat!=="all")list=list.filter(function(a){return a.cat===filterCat;});
  if(searchTerm)list=list.filter(function(a){return(a.t+a.d).toLowerCase().indexOf(searchTerm)>=0;});
  var rank={legend:0,epic:1,rare:2,uncommon:3,common:4};
  list.sort(function(a,b){var ua=!!state.unlocked[a.id],ub=!!state.unlocked[b.id];if(ua!==ub)return ua?-1:1;return rank[a.rarity]-rank[b.rarity];});
  byId("grid").innerHTML=list.length?list.map(cardHTML).join(""):'<div class="empty">Квестов не найдено. Смени фильтр или создай свой!</div>';
  Array.prototype.forEach.call(byId("grid").querySelectorAll(".card"),function(c){c.onclick=function(){toggle(c.getAttribute("data-id"));};});
}
function renderShowcase(){
  var rank={legend:0,epic:1,rare:2,uncommon:3,common:4};
  var unl=unlockedList().sort(function(a,b){return rank[a.rarity]-rank[b.rarity];}).slice(0,9);
  byId("showcase").innerHTML=unl.length?unl.map(cardHTML).join(""):'<div class="empty">Пока пусто. Открой первый квест во вкладке КВЕСТЫ — и он появится тут!</div>';
  Array.prototype.forEach.call(byId("showcase").querySelectorAll(".card"),function(c){c.onclick=function(){toggle(c.getAttribute("data-id"));};});
}
function toggle(id){
  var a=allAch().filter(function(x){return x.id===id;})[0];if(!a)return;
  var lvlBefore=computeStats().level;
  if(state.unlocked[id]){delete state.unlocked[id];}
  else{state.unlocked[id]={date:new Date().toLocaleDateString("ru-RU",{day:"numeric",month:"short",year:"numeric"})};showToast(a);}
  save();renderAll();
  var lvlAfter=computeStats().level;
  if(lvlAfter>lvlBefore){setTimeout(function(){showLevelUp(lvlAfter);},600);}
}
var toastTimer;
function showToast(a){
  var r=RARITY[a.rarity];
  byId("toast-icon").innerHTML=iconSVG(a.ic);
  byId("toast-t").textContent="QUEST COMPLETE!";
  byId("toast-s").textContent=a.t+" — "+r.label+" — +"+r.xp+"XP";
  var t=byId("toast");t.classList.remove("levelup");
  t.classList.add("show");clearTimeout(toastTimer);
  toastTimer=setTimeout(function(){t.classList.remove("show");},2800);
}
function showLevelUp(lvl){
  byId("toast-icon").innerHTML=iconSVG("trophy");
  byId("toast-t").textContent="LEVEL UP!";
  byId("toast-s").textContent="Ты достигла "+lvl+" уровня!";
  var t=byId("toast");t.classList.add("levelup","show");clearTimeout(toastTimer);
  toastTimer=setTimeout(function(){t.classList.remove("show","levelup");},3200);
}
function renderAll(){renderStats();renderGrid();renderShowcase();}

Array.prototype.forEach.call(document.querySelectorAll(".chip"),function(ch){ch.onclick=function(){
  Array.prototype.forEach.call(document.querySelectorAll(".chip"),function(x){x.classList.remove("active");});
  ch.classList.add("active");filterCat=ch.getAttribute("data-cat");renderGrid();};});
byId("search").oninput=function(e){searchTerm=e.target.value.toLowerCase().trim();renderGrid();};
var addBtn=byId("c-add");
if(addBtn)addBtn.onclick=function(){
  var t=byId("c-title").value.trim();if(!t){byId("c-title").focus();return;}
  var a={id:"custom-"+Date.now(),t:t.toUpperCase(),d:byId("c-desc").value.trim(),cat:byId("c-cat").value,ic:"star",rarity:byId("c-rarity").value,pct:0};
  state.custom.push(a);
  state.unlocked[a.id]={date:new Date().toLocaleDateString("ru-RU",{day:"numeric",month:"short",year:"numeric"})};
  byId("c-title").value="";byId("c-desc").value="";save();renderAll();showToast(a);
};

var ageInput=byId("age-input");
if(state.age!==null&&state.age!==undefined)ageInput.value=state.age;
function commitAge(){
  var v=parseInt(ageInput.value,10);
  if(isNaN(v)){state.age=null;ageInput.value="";}
  else{v=Math.min(100,Math.max(0,v));state.age=v;ageInput.value=v;}
  save();renderStats();
}
ageInput.oninput=function(){var v=parseInt(ageInput.value,10);state.age=isNaN(v)?null:Math.min(100,Math.max(0,v));renderStats();};
ageInput.onblur=commitAge;
ageInput.onkeydown=function(e){if(e.key==="Enter"){ageInput.blur();}};

Array.prototype.forEach.call(document.querySelectorAll(".tab"),function(tb){tb.onclick=function(){
  Array.prototype.forEach.call(document.querySelectorAll(".tab"),function(x){x.classList.remove("active");});tb.classList.add("active");
  Array.prototype.forEach.call(document.querySelectorAll(".view"),function(v){v.classList.remove("active");});
  byId("view-"+tb.getAttribute("data-view")).classList.add("active");window.scrollTo({top:0,behavior:"smooth"});};});

byId("p-copy").onclick=function(){
  if(navigator.clipboard)navigator.clipboard.writeText(byId("p-link").textContent);
  var o=byId("p-copy").textContent;byId("p-copy").textContent="ГОТОВО!";setTimeout(function(){byId("p-copy").textContent=o;},1500);
};
var _initLvl=computeStats().level;
document.getElementById("scene-hero").innerHTML=girlSVG(_initLvl);
document.getElementById("avatar-box").innerHTML=girlSVG(_initLvl);
renderAll();